import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";

export function SobaDetalji() {
  const { idSoba } = useParams();
  const [rezervacije, setRezervacije] = useState([]);
  const [datumOd, setDatumOd] = useState("");
  const [datumDo, setDatumDo] = useState("");
  const [brojOsoba, setBrojOsoba] = useState("");
  const [soba, setSoba] = useState(null);
  const [emailGost, setEmailGost] = useState("");

  // ID ulogovanog recepcionara iz cookie-a
  const recepcionarId = parseInt(document.cookie.split("userId=")[1]?.split(";")[0]);

  useEffect(() => {
    fetch(`http://localhost:8080/rooms/${idSoba}`)
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.value) setSoba(data.data.value);
      })
      .catch((err) => console.error("Greška pri učitavanju sobe:", err));
  }, [idSoba]);

  useEffect(() => {
    fetch(`http://localhost:8080/reservations/getReservationsForRoom/${idSoba}`)
      .then((res) => res.json())
      .then((data) => {
        if (data?.data?.values) setRezervacije(data.data.values);
      })
      .catch((err) => console.error("Greška pri učitavanju rezervacija za sobu:", err));
  }, [idSoba]);

  const handleAddReservation = async (e) => {
    e.preventDefault();

    if (!soba) {
      alert("Podaci o sobi nisu učitani.");
      return;
    }

    if (!emailGost) {
      alert("Unesite email gosta.");
      return;
    }

    if (!datumOd || !datumDo || !brojOsoba) {
      alert("Popunite sve podatke za rezervaciju.");
      return;
    }

    const datumP = new Date(datumOd);
    const datumO = new Date(datumDo);
    const brojNoci = Math.ceil((datumO - datumP) / (1000 * 60 * 60 * 24));

    if (brojNoci <= 0) {
      alert("Datum odjave mora biti posle datuma prijave!");
      return;
    }

    const ukupanIznos = soba.tipSobe?.cenaPoNoci * brojNoci * parseInt(brojOsoba);

    const novaRez = {
      datumPrijave: datumOd,
      datumOdjave: datumDo,
      brojOsoba: parseInt(brojOsoba),
      statusRezervacije: "CONFIRMED",
      gost: { email: emailGost }, // koristimo samo email, backend mora da kreira/nađe gosta
      soba: { idSoba: parseInt(idSoba) },
      recepcionar: { idRecepcionar: recepcionarId },
      ukupanIznos,
      datumKreiranja: new Date().toISOString().split("T")[0],
    };

    try {
      const response = await fetch(
        "http://localhost:8080/reservations/createByReceptionist",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(novaRez),
        }
      );

      if (!response.ok) {
        const errData = await response.json();
        console.error("Backend error:", errData);
        alert("Greška pri kreiranju rezervacije: " + (errData.message || "Nepoznata greška"));
        return;
      }

      const data = await response.json();
      alert(data.message || "Rezervacija je uspešno dodata!");
      setRezervacije((prev) => [...prev, novaRez]);
      setDatumOd("");
      setDatumDo("");
      setBrojOsoba("");
      setEmailGost("");
    } catch (err) {
      console.error("Greška:", err);
      alert("Greška pri kreiranju rezervacije!");
    }
  };

  return (
    <>
      <NavBarRecepcionar />
      <div style={{ padding: "40px" }}>
        <h2>Rezervacije za sobu #{idSoba}</h2>

        {rezervacije.length > 0 ? (
          <table style={{ width: "100%", borderCollapse: "collapse", marginTop: "20px" }}>
            <thead>
              <tr style={{ backgroundColor: "#e7b7ffff" }}>
                <th>ID</th>
                <th>Gost</th>
                <th>Datum prijave</th>
                <th>Datum odjave</th>
                <th>Broj osoba</th>
                <th>Ukupan iznos (RSD)</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {rezervacije.map((r, index) => (
                <tr key={index}>
                  <td>{r.idRezervacija || "-"}</td>
                  <td>{r.gost?.email || "Nepoznat"}</td>
                  <td>{r.datumPrijave}</td>
                  <td>{r.datumOdjave}</td>
                  <td>{r.brojOsoba}</td>
                  <td>{r.ukupanIznos?.toFixed(2) || "-"}</td>
                  <td>{r.statusRezervacije}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p>Nema rezervacija za ovu sobu.</p>
        )}

        <hr style={{ margin: "30px 0" }} />

        <h3>Kreiraj novu rezervaciju</h3>
        <form onSubmit={handleAddReservation}>
          <label>Email gosta:</label>
          <input
            type="email"
            value={emailGost}
            onChange={(e) => setEmailGost(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px", width: "300px" }}
          />

          <label>Datum prijave:</label>
          <input
            type="date"
            value={datumOd}
            onChange={(e) => setDatumOd(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px" }}
          />

          <label>Datum odjave:</label>
          <input
            type="date"
            value={datumDo}
            onChange={(e) => setDatumDo(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px" }}
          />

          <label>Broj osoba:</label>
          <input
            type="number"
            value={brojOsoba}
            onChange={(e) => setBrojOsoba(e.target.value)}
            required
            style={{ display: "block", marginBottom: "10px", width: "100px" }}
          />

          {datumOd && datumDo && brojOsoba && soba && (
            <p style={{ marginTop: "10px", fontWeight: "bold" }}>
              Ukupan iznos:{" "}
              {(soba.tipSobe.cenaPoNoci *
                Math.ceil((new Date(datumDo) - new Date(datumOd)) / (1000 * 60 * 60 * 24)) *
                brojOsoba
              ).toFixed(2)}{" "}
              RSD
            </p>
          )}

          <button
            type="submit"
            style={{
              backgroundColor: "#b84aff",
              color: "white",
              border: "none",
              padding: "8px 15px",
              borderRadius: "6px",
              cursor: "pointer",
            }}
          >
            Dodaj rezervaciju
          </button>
        </form>
      </div>
      <Footer />
    </>
  );
}
